SELECT count(*) FROM kind_type, title, movie_info, info_type, movie_companies, cast_info, name, char_name, role_type WHERE title.kind_id = kind_type.id AND movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id AND movie_companies.movie_id = title.id AND cast_info.movie_id = title.id AND cast_info.person_id = name.id AND cast_info.person_role_id = char_name.id AND cast_info.role_id = role_type.id;